#include <string.h>

#define MAX_THREADS 4
#define MAX_RETIRED 8

typedef struct Node {
    int value;
    struct Node *next;
} Node;

Node *head = NULL;
Node *hazard_ptrs[MAX_THREADS] = {NULL};

typedef struct {
    Node *retired[MAX_RETIRED];
    int count;
} RetiredList;

__thread int thread_id_local;
__thread RetiredList retired_list = {{NULL}, 0};

void hp_set(int tid, Node *ptr) {
    __atomic_store_n(&hazard_ptrs[____], ptr, __ATOMIC_RELEASE);
}

void hp_clear(int tid) {
    __atomic_store_n(&hazard_ptrs[tid], ____, __ATOMIC_RELEASE);
}

int is_hazardous(Node *ptr) {
    for (int i = 0; i < MAX_THREADS; i++) {
        if (__atomic_load_n(&hazard_ptrs[i], __ATOMIC_ACQUIRE) == ____)
            return 1;
    }
    return 0;
}

void retire_node(Node *ptr) {
    retired_list.retired[retired_list.count++] = ptr;
    if (retired_list.count >= MAX_RETIRED) {
        int new_count = 0;
        for (int i = 0; i < retired_list.count; i++) {
            if (is_hazardous(retired_list.retired[i])) {
                retired_list.retired[new_count++] = retired_list.retired[i];
            } else {
                free(retired_list.retired[i]);
